window.addEventListener('message', function(event) {
  if (event.origin !== 'https://confde.fenstermaxx24.com') return;

  switch(event.data) {
    case 'addWarenkorb':
      // Update cart count in navigation
      // Show success notification
      updateCartCount();
      showNotification('Artikel wurde zum Warenkorb hinzugefügt');
      break;
    case 'do_continue':
      // User wants to continue configuring
      break;
    case 'do_restart':
      // Reload iframe to reset configuration
      document.getElementById('configurator-iframe').src = document.getElementById('configurator-iframe').src;
      break;
  }
});
